# Simple calc inline
def hex_to_rgb(h):
    h = h.lstrip('#')
    return tuple(int(h[i:i+2], 16) for i in (0, 2, 4))

def rel_lum(rgb):
    vals = [(c/255.0) for c in rgb]
    vals = [(v/12.92 if v<=0.03928 else ((v+0.055)/1.055)**2.4) for v in vals]
    return 0.2126*vals[0] + 0.7152*vals[1] + 0.0722*vals[2]

def ratio(c1, c2):
    l1 = rel_lum(hex_to_rgb(c1))
    l2 = rel_lum(hex_to_rgb(c2))
    return round((max(l1,l2)+0.05)/(min(l1,l2)+0.05), 2)

print(f"Accent #C23579 on bg #FAFAFE: {ratio('#C23579', '#FAFAFE')}:1")
print(f"White on accent #C23579: {ratio('#FFFFFF', '#C23579')}:1")
"}

